_H = "xmlns='http://www.w3.org/2000/svg' fill='none' viewBox='0 0 24 24'"

def _svg(paths, w=22, sw="1.6"):
    s = sw.replace(".", "_")
    return (f"<svg {_H} width='{w}' height='{w}' "
            f"stroke='#f50f12' stroke-width='{sw}'>{paths}</svg>")

