SICO_SPO = _svg("<path stroke-linecap='round' stroke-linejoin='round' d='M15.75 6a3.75 3.75 0 1 1-7.5 0 3.75 3.75 0 0 1 7.5 0ZM4.501 20.118a7.5 7.5 0 0 1 14.998 0A17.933 17.933 0 0 1 12 21.75c-2.676 0-5.216-.584-7.499-1.632Z'/>", w=15, sw="1.8")

sec(SICO_SPO, "SPO-Wise (MR Name) Analysis")

# ── compute SPO summary ────────────────────────────────────────────────────
spo_sum = (
    df.groupby("Head Qtr", as_index=False)
      .agg(
          Revenue   = ("Sales Amt",   "sum"),
          Qty       = ("Sales Qty",   "sum"),
          SKUs      = ("Product Name","nunique"),
          States    = ("State Name",  "nunique"),
          Divisions = ("Division Name","nunique"),
      )
      .sort_values("Revenue", ascending=False)
      .reset_index(drop=True)
)

# MoM for each SPO
monthly_spo = (
    df.groupby(["Head Qtr", "Month_Period"], as_index=False)["Sales Amt"].sum()
      .sort_values(["Head Qtr","Month_Period"])
)
spo_periods = sorted(df["Month_Period"].unique())
if len(spo_periods) >= 2:
    last_p, prev_p = spo_periods[-1], spo_periods[-2]
    last_rev = monthly_spo[monthly_spo["Month_Period"]==last_p].set_index("Head Qtr")["Sales Amt"]
    prev_rev = monthly_spo[monthly_spo["Month_Period"]==prev_p].set_index("Head Qtr")["Sales Amt"]
    spo_sum["MoM %"] = spo_sum["Head Qtr"].map(
        lambda h: round((last_rev.get(h,0)-prev_rev.get(h,0))/prev_rev.get(h,1)*100,1)
        if prev_rev.get(h,0) else None
    )
else:
    spo_sum["MoM %"] = None

# ── ROW 1: Top SPO bar + SPO revenue donut ────────────────────────────────
